settings.customCss:
.mf-form-root { background:#f8fafc; }
.mf-form-actions { display:none !important; }
.mfdr-dnn-tabs-cascade .mfdr-toolbar { margin-bottom: 12px; }
.mfdr-dnn-tabs-cascade .mfdr-table { width:100%; border-collapse:collapse; background:#fff; border-radius:14px; overflow:hidden; }
.mfdr-dnn-tabs-cascade .mfdr-table th,
.mfdr-dnn-tabs-cascade .mfdr-table td { padding:10px 12px; border-bottom:1px solid #e5e7eb; text-align:left; font-size:13px; }
.mfdr-dnn-tabs-cascade .mfdr-table th { background:#f8fafc; color:#475569; font-size:11px; text-transform:uppercase; letter-spacing:.06em; }
.mfdr-dnn-tabs-cascade .mfdr-drill { color:#4338ca; font-weight:700; text-decoration:none; }
.mfdr-dnn-tabs-cascade .mfdr-drill:hover { text-decoration:underline; }
